// ─── Helpers ──────────────────────────────────────────────────────────────────

function getInitials(name) {
  return name
    .split(" ")
    .map((n) => n[0])
    .join("")
    .slice(0, 2)
    .toUpperCase();
}

function yearsInBusiness(foundedYear) {
  return new Date().getFullYear() - foundedYear;
}

// ─── Generator ────────────────────────────────────────────────────────────────

function generateSiteData() {
  const cfg = clientConfig;

  // siteConfig — business identity consumed by Header, Footer, layout metadata
  const _years = yearsInBusiness(cfg.foundedYear);
  const siteConfig = {
    businessName: cfg.businessName,
    logoMain: cfg.logoMain || cfg.businessName,
    logoAccent: cfg.logoAccent || "",
    aboutBrief:
      cfg.aboutBrief || `${cfg.city}'s trusted team since ${cfg.foundedYear}.`,
    tagline: cfg.tagline,
    city: cfg.city,
    state: cfg.state,
    phone: cfg.phone,
    email: cfg.email,
    address: cfg.address,
    zipCode: cfg.zipCode,
    website: cfg.website,
    heroHeadline: cfg.heroHeadline,
    heroSubtext: cfg.heroSubtext,
    aboutStory: cfg.aboutStory,
    serviceAreas: cfg.serviceAreas,
    foundedYear: cfg.foundedYear,
    yearsInBusiness: _years,
    projectsCompleted: cfg.projectsCompleted,
    satisfactionRate: cfg.satisfactionRate,
    instagramUrl: cfg.instagramUrl || "",
    facebookUrl: cfg.facebookUrl || "",
    yelpUrl: cfg.yelpUrl || "",
    houzzUrl: cfg.houzzUrl || "",
  };

  // services — only the ones flagged true in clientConfig.services
  const services = Object.entries(cfg.services)
    .filter(([, active]) => active)
    .map(([key]) => SERVICE_TEMPLATES[key])
    .filter(Boolean);

  // projects — map clientConfig shape → component shape
  const projects = cfg.projects.map((p, i) => ({
    id: i + 1,
    title: p.title,
    category: p.category,
    shortDescription: p.shortDescription,
    fullDescription: p.fullDescription,
    beforeImages: [p.beforeImage || defaultAssets.defaultProjectBefore],
    afterImages: [p.afterImage || defaultAssets.defaultProjectAfter],
    materials: p.materials || [],
    duration: p.duration || "TBD",
    budgetRange: p.budget || "Contact for pricing",
    featured: p.featured || false,
    testimonial: p.testimonial || null,
  }));

  // testimonials — map clientConfig reviews → component shape
  const testimonials = cfg.reviews.map((r, i) => ({
    id: i + 1,
    quote: r.text,
    author: r.author,
    location: r.location || cfg.city,
    rating: r.rating || 5,
    projectType: r.project || "Renovation",
    date: r.date || "",
  }));

  // teamMembers — map clientConfig team → component shape
  const teamMembers = cfg.team.map((m, i) => ({
    id: i + 1,
    name: m.name,
    title: m.role,
    yearsExperience: m.yearsExperience || 10,
    bio: m.bio || "",
    initials: getInitials(m.name),
    photo: m.photo || null,
  }));

  // stats — derived from clientConfig numbers
  const stats = [
    {
      label: "Projects Completed",
      value: cfg.projectsCompleted,
      suffix: "+",
      prefix: "",
    },
    {
      label: "Client Satisfaction",
      value: cfg.satisfactionRate,
      suffix: "%",
      prefix: "",
    },
    {
      label: "Years in Business",
      value: yearsInBusiness(cfg.foundedYear),
      suffix: "",
      prefix: "",
    },
    {
      label: "Hidden Fees",
      value: cfg.hiddenFees ?? 0,
      suffix: "",
      prefix: "$",
    },
  ];

  // socialProofMessages — combine people + actions from clientConfig
  const people = cfg.socialProofPeople || [
    { name: "A homeowner", city: cfg.city },
  ];
  const actions = cfg.socialProofActions || ["just booked a consultation"];
  const socialProofMessages = people.map((p, i) => ({
    name: p.name,
    city: p.city,
    action: actions[i % actions.length],
  }));

  return {
    siteConfig,
    services,
    projects,
    testimonials,
    teamMembers,
    stats,
    socialProofMessages,
  };
}

export default generateSiteData;
